import{_ as e,o as i,c as s,a2 as t}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"किसी मौजूदा Spatie install से माइग्रेट करना","description":"","frontmatter":{},"headers":[],"relativePath":"hi/guide/migration.md","filePath":"hi/guide/migration.md"}'),l={name:"hi/guide/migration.md"};function c(d,a,o,n,r,h){return i(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="किसी-मौजूदा-spatie-install-से-माइग्रेट-करना" tabindex="-1">किसी मौजूदा Spatie install से माइग्रेट करना <a class="header-anchor" href="#किसी-मौजूदा-spatie-install-से-माइग्रेट-करना" aria-label="Permalink to &quot;किसी मौजूदा Spatie install से माइग्रेट करना&quot;">​</a></h1><p>यदि आपका एप्लिकेशन पहले से <code>spatie/laravel-permission</code> का उपयोग मौजूदा भूमिकाओं, अनुमतियों और असाइनमेंट के साथ करता है, तो <code>clearance:install</code> इन्हें पहचानता है और सुरक्षित रखता है - यदि <code>roles</code> टेबल पहले से मौजूद है तो यह कभी भी Spatie के migrations नहीं चलाता। पूरे install फ्लो के लिए देखें <a href="/clearance-docs/hi/guide/installation.html">इंस्टॉलेशन</a>।</p><p>एक बार इंस्टॉल हो जाने पर, अपनी मौजूदा भूमिकाओं और गार्ड्स पर Clearance के अपने मेटाडेटा को अपनाने के लिए <code>clearance:backfill</code> का उपयोग करें।</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # meta + role scope + guards</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --only=meta</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # just one section</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # preview, no writes</span></span></code></pre></div><h2 id="हर-सेक्शन-क्या-करता-है" tabindex="-1">हर सेक्शन क्या करता है <a class="header-anchor" href="#हर-सेक्शन-क्या-करता-है" aria-label="Permalink to &quot;हर सेक्शन क्या करता है&quot;">​</a></h2><table tabindex="0"><thead><tr><th>सेक्शन</th><th>प्रभाव</th></tr></thead><tbody><tr><td><code>meta</code></td><td>बिना meta वाली हर भूमिका के लिए <code>clr_meta</code> डिस्प्ले नाम (title-cased भूमिका नाम) सीड करता है।</td></tr><tr><td><code>roles</code></td><td>बिना meta वाली हर भूमिका के लिए <code>clr_role_meta</code> डिफ़ॉल्ट्स (<code>scope=global</code>, <code>is_locked=false</code>) सीड करता है।</td></tr><tr><td><code>guards</code></td><td><code>config(&#39;auth.guards&#39;)</code> से गार्ड्स को <code>clr_guards</code> में import करता है, <code>allowed_guard_drivers</code> द्वारा फ़िल्टर किया गया।</td></tr></tbody></table><p>केवल एक सेक्शन चलाने के लिए, तीनों के बजाय <code>--only=&lt;section&gt;</code> का उपयोग करें।</p><div class="tip custom-block"><p class="custom-block-title">Idempotent</p><p>सभी सेक्शन idempotent हैं - <code>clearance:backfill</code> को दोबारा चलाना सुरक्षित है और यह मौजूदा <code>clr_*</code> रो को डुप्लिकेट या ओवरराइट नहीं करेगा।</p></div><h2 id="edge-cases" tabindex="-1">Edge cases <a class="header-anchor" href="#edge-cases" aria-label="Permalink to &quot;Edge cases&quot;">​</a></h2><p>पैकेज रिपॉज़िटरी में एक अधिक विस्तृत माइग्रेशन गाइड है जो यहां न बताए गए edge cases को कवर करती है - विशेष रूप से तब क्या होता है जब आपके डेटाबेस में पहले से <code>super_admin</code> (या किसी alias जैसे <code>superadmin</code>, <code>root</code>, <code>owner</code>) नाम की एक भूमिका मौजूद हो जो Clearance की अपनी <code>super_admin</code> भूमिका से टकराती है, साथ ही कस्टम <code>Role</code>/<code>Permission</code> मॉडल subclasses और गार्ड import व्यवहार पर नोट्स। किसी production डेटाबेस को गैर-तुच्छ मौजूदा भूमिका डेटा के साथ backfill करने से पहले इसे पढ़ें। <code>clearance:install</code> के दौरान alias detection व्यवहार के लिए <a href="/clearance-docs/hi/features/super-admin.html">सुपर एडमिन</a> भी देखें।</p><h2 id="संबंधित" tabindex="-1">संबंधित <a class="header-anchor" href="#संबंधित" aria-label="Permalink to &quot;संबंधित&quot;">​</a></h2><ul><li><a href="/clearance-docs/hi/guide/installation.html">इंस्टॉलेशन</a> - पूरा <code>clearance:install</code> फ्लो</li><li><a href="/clearance-docs/hi/api/artisan-commands.html">Artisan कमांड</a> - पूरा कमांड संदर्भ</li><li><a href="/clearance-docs/hi/guide/architecture.html">आर्किटेक्चर</a> - वे <code>clr_*</code> टेबल्स जिन्हें backfill भरता है</li></ul>`,12)])])}const m=e(l,[["render",c]]);export{k as __pageData,m as default};
